from functools import wraps

def with_kill_switch(flag_name: str, fallback_fn=None):
    """Decorator that wraps a function with a kill switch."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if not client.is_enabled(flag_name):
                if fallback_fn:
                    return fallback_fn(*args, **kwargs)
                raise FeatureDisabledError(flag_name)
            return func(*args, **kwargs)
        return wrapper
    return decorator

# Usage:
