import json
import os

FLAG_DEFAULTS = {
    "release.checkout.new-payment-flow": False,  # new feature: default off
    "ops.payments.stripe-processing": True,       # existing feature: default on
    "experiment.growth.signup-redesign": False,
}

CACHE_FILE = "/tmp/flag-cache.json"

def get_flag(flag_name: str, context: dict) -> bool:
    try:
        result = client.is_enabled(flag_name, context)
        # Update local cache on success
        _update_cache(flag_name, result)
        return result
    except Exception:
        # Try local cache first
        cached = _read_cache(flag_name)
        if cached is not None:
            return cached
        # Fall back to hardcoded defaults
        return FLAG_DEFAULTS.get(flag_name, False)

def _update_cache(flag_name, value):
    cache = {}
    if os.path.exists(CACHE_FILE):
        with open(CACHE_FILE) as f:
            cache = json.load(f)
    cache[flag_name] = value
    with open(CACHE_FILE, "w") as f:
        json.dump(cache, f)

def _read_cache(flag_name):
    if os.path.exists(CACHE_FILE):
        with open(CACHE_FILE) as f:
            return json.load(f).get(flag_name)
    return None
